uniform 	vec4 hlslcc_mtx4x4unity_ObjectToWorld[4];
uniform 	vec4 hlslcc_mtx4x4unity_WorldToObject[4];
uniform 	vec4 hlslcc_mtx4x4unity_MatrixVP[4];
uniform 	vec4 _MainTex_ST;
in highp vec4 in_POSITION0;
in highp vec3 in_NORMAL0;
in highp vec2 in_TEXCOORD0;
out highp vec2 vs_TEXCOORD0;
out highp vec2 vs_TEXCOORD1;
out highp vec3 vs_TEXCOORD2;
out highp vec3 vs_TEXCOORD3;
vec4 u_xlat0;
vec4 u_xlat1;
float u_xlat6;
void main()
{
    u_xlat0 = in_POSITION0.yyyy * hlslcc_mtx4x4unity_ObjectToWorld[1];
    u_xlat0 = hlslcc_mtx4x4unity_ObjectToWorld[0] * in_POSITION0.xxxx + u_xlat0;
    u_xlat0 = hlslcc_mtx4x4unity_ObjectToWorld[2] * in_POSITION0.zzzz + u_xlat0;
    u_xlat1 = u_xlat0 + hlslcc_mtx4x4unity_ObjectToWorld[3];
    vs_TEXCOORD3.xyz = hlslcc_mtx4x4unity_ObjectToWorld[3].xyz * in_POSITION0.www + u_xlat0.xyz;
    u_xlat0 = u_xlat1.yyyy * hlslcc_mtx4x4unity_MatrixVP[1];
    u_xlat0 = hlslcc_mtx4x4unity_MatrixVP[0] * u_xlat1.xxxx + u_xlat0;
    u_xlat0 = hlslcc_mtx4x4unity_MatrixVP[2] * u_xlat1.zzzz + u_xlat0;
    gl_Position = hlslcc_mtx4x4unity_MatrixVP[3] * u_xlat1.wwww + u_xlat0;
    vs_TEXCOORD0.xy = in_TEXCOORD0.xy * _MainTex_ST.xy + _MainTex_ST.zw;
    vs_TEXCOORD1.xy = in_TEXCOORD0.xy;
    u_xlat0.x = dot(in_NORMAL0.xyz, hlslcc_mtx4x4unity_WorldToObject[0].xyz);
    u_xlat0.y = dot(in_NORMAL0.xyz, hlslcc_mtx4x4unity_WorldToObject[1].xyz);
    u_xlat0.z = dot(in_NORMAL0.xyz, hlslcc_mtx4x4unity_WorldToObject[2].xyz);
    u_xlat6 = dot(u_xlat0.xyz, u_xlat0.xyz);
    u_xlat6 = inversesqrt(u_xlat6);
    vs_TEXCOORD2.xyz = vec3(u_xlat6) * u_xlat0.xyz;
    return;
}


#version 300 es

precision highp float;
precision highp int;
#define HLSLCC_ENABLE_UNIFORM_BUFFERS 0
#if HLSLCC_ENABLE_UNIFORM_BUFFERS
#define UNITY_UNIFORM
#else
#define UNITY_UNIFORM uniform
#endif
#define UNITY_SUPPORTS_UNIFORM_LOCATION 0
#if UNITY_SUPPORTS_UNIFORM_LOCATION
#define UNITY_LOCATION(x) layout(location = x)
#define UNITY_BINDING(x) layout(binding = x, std140)
#else
#define UNITY_LOCATION(x)
#define UNITY_BINDING(x) layout(std140)
#endif
uniform 	vec3 _WorldSpaceCameraPos;
uniform 	vec4 _WorldSpaceLightPos0;
uniform 	mediump vec4 _LightColor0;
uniform 	mediump vec4 _LeftColor;
uniform 	mediump vec4 _RightColor;
uniform 	mediump vec4 _LeftShadowColor;
uniform 	mediump vec4 _RightShadowColor;
uniform 	float _BlendOffset;
uniform 	float _BlendSoftness;
uniform 	float _UseCustomLightDirection;
uniform 	float _CustomLightYaw;
uniform 	float _CustomLightPitch;
uniform 	float _RampThreshold;
uniform 	float _RampSoftness;
uniform 	float _RampStrength;
uniform 	mediump vec4 _LightTint;
uniform 	float _Brightness;
uniform 	float _UseSpecular;
uniform 	mediump vec4 _SpecularColor;
uniform 	float _SpecularIntensity;
uniform 	float _SpecularThreshold;
uniform 	float _SpecularSoftness;
uniform 	float _SpecularSharpness;
uniform 	float _SpecularOnlyLightArea;
uniform 	float _SpecularUseLightColor;
UNITY_LOCATION(0) uniform mediump sampler2D _MainTex;
in highp vec2 vs_TEXCOORD0;
in highp vec2 vs_TEXCOORD1;
in highp vec3 vs_TEXCOORD2;
in highp vec3 vs_TEXCOORD3;
layout(location = 0) out mediump vec4 SV_Target0;
vec3 u_xlat0;
vec3 u_xlat1;
vec4 u_xlat2;
float u_xlat3;
mediump vec4 u_xlat16_3;
float u_xlat4;
mediump vec4 u_xlat16_4;
mediump vec3 u_xlat16_5;
vec3 u_xlat6;
vec3 u_xlat7;
vec3 u_xlat8;
float u_xlat14;
float u_xlat21;
void main()
{
    u_xlat0.xyz = (-vs_TEXCOORD3.xyz) * _WorldSpaceLightPos0.www + _WorldSpaceLightPos0.xyz;
    u_xlat21 = dot(u_xlat0.xyz, u_xlat0.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat0.xyz = vec3(u_xlat21) * u_xlat0.xyz;
    u_xlat21 = _CustomLightYaw * 0.0174532924;
    u_xlat1.x = sin(u_xlat21);
    u_xlat2.x = cos(u_xlat21);
    u_xlat21 = _CustomLightPitch * 0.0174532924;
    u_xlat3 = sin(u_xlat21);
    u_xlat4 = cos(u_xlat21);
    u_xlat1.x = u_xlat1.x * u_xlat4;
    u_xlat1.z = u_xlat2.x * u_xlat4;
    u_xlat1.y = u_xlat3;
    u_xlat21 = dot(u_xlat1.xyz, u_xlat1.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat1.xyz = u_xlat1.xyz * vec3(u_xlat21) + (-u_xlat0.xyz);
    u_xlat0.xyz = vec3(vec3(_UseCustomLightDirection, _UseCustomLightDirection, _UseCustomLightDirection)) * u_xlat1.xyz + u_xlat0.xyz;
    u_xlat21 = dot(u_xlat0.xyz, u_xlat0.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat0.xyz = vec3(u_xlat21) * u_xlat0.xyz;
    u_xlat1.xyz = (-vs_TEXCOORD3.xyz) + _WorldSpaceCameraPos.xyz;
    u_xlat21 = dot(u_xlat1.xyz, u_xlat1.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat1.xyz = u_xlat1.xyz * vec3(u_xlat21) + u_xlat0.xyz;
    u_xlat21 = dot(u_xlat1.xyz, u_xlat1.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat1.xyz = vec3(u_xlat21) * u_xlat1.xyz;
    u_xlat21 = dot(vs_TEXCOORD2.xyz, vs_TEXCOORD2.xyz);
    u_xlat21 = inversesqrt(u_xlat21);
    u_xlat2.xyz = vec3(u_xlat21) * vs_TEXCOORD2.xyz;
    u_xlat21 = dot(u_xlat2.xyz, u_xlat1.xyz);
    u_xlat21 = clamp(u_xlat21, 0.0, 1.0);
    u_xlat0.x = dot(u_xlat2.xyz, u_xlat0.xyz);
    u_xlat0.x = clamp(u_xlat0.x, 0.0, 1.0);
    u_xlat7.x = (-_SpecularSoftness) + _SpecularThreshold;
    u_xlat14 = (-u_xlat7.x) + u_xlat21;
    u_xlat21 = _SpecularSoftness + _SpecularThreshold;
    u_xlat7.x = (-u_xlat7.x) + u_xlat21;
    u_xlat7.x = float(1.0) / u_xlat7.x;
    u_xlat7.x = u_xlat7.x * u_xlat14;
    u_xlat7.x = clamp(u_xlat7.x, 0.0, 1.0);
    u_xlat14 = u_xlat7.x * -2.0 + 3.0;
    u_xlat7.x = u_xlat7.x * u_xlat7.x;
    u_xlat7.x = u_xlat7.x * u_xlat14;
    u_xlat7.x = log2(u_xlat7.x);
    u_xlat7.x = u_xlat7.x * _SpecularSharpness;
    u_xlat7.x = exp2(u_xlat7.x);
    u_xlat14 = (-_RampSoftness) + _RampThreshold;
    u_xlat0.x = (-u_xlat14) + u_xlat0.x;
    u_xlat21 = _RampSoftness + _RampThreshold;
    u_xlat14 = (-u_xlat14) + u_xlat21;
    u_xlat14 = float(1.0) / u_xlat14;
    u_xlat0.x = u_xlat14 * u_xlat0.x;
    u_xlat0.x = clamp(u_xlat0.x, 0.0, 1.0);
    u_xlat14 = u_xlat0.x * -2.0 + 3.0;
    u_xlat0.x = u_xlat0.x * u_xlat0.x;
    u_xlat21 = u_xlat14 * u_xlat0.x + -1.0;
    u_xlat0.x = u_xlat0.x * u_xlat14;
    u_xlat14 = _SpecularOnlyLightArea * u_xlat21 + 1.0;
    u_xlat7.x = u_xlat14 * u_xlat7.x;
    u_xlat1.xyz = _LightColor0.xyz + vec3(-1.0, -1.0, -1.0);
    u_xlat1.xyz = vec3(vec3(_SpecularUseLightColor, _SpecularUseLightColor, _SpecularUseLightColor)) * u_xlat1.xyz + vec3(1.0, 1.0, 1.0);
    u_xlat16_5.xyz = u_xlat1.xyz * _SpecularColor.xyz;
    u_xlat1.xyz = u_xlat16_5.xyz * vec3(_SpecularIntensity);
    u_xlat7.xyz = u_xlat7.xxx * u_xlat1.xyz;
    u_xlat1.x = _BlendSoftness + _BlendOffset;
    u_xlat8.x = (-_BlendSoftness) + _BlendOffset;
    u_xlat1.x = (-u_xlat8.x) + u_xlat1.x;
    u_xlat8.x = (-u_xlat8.x) + vs_TEXCOORD1.x;
    u_xlat1.x = float(1.0) / u_xlat1.x;
    u_xlat1.x = u_xlat1.x * u_xlat8.x;
    u_xlat1.x = clamp(u_xlat1.x, 0.0, 1.0);
    u_xlat8.x = u_xlat1.x * -2.0 + 3.0;
    u_xlat1.x = u_xlat1.x * u_xlat1.x;
    u_xlat1.x = u_xlat1.x * u_xlat8.x;
    u_xlat8.xyz = (-_LeftShadowColor.xyz) + _RightShadowColor.xyz;
    u_xlat8.xyz = u_xlat1.xxx * u_xlat8.xyz + _LeftShadowColor.xyz;
    u_xlat2 = (-_LeftColor) + _RightColor;
    u_xlat2 = u_xlat1.xxxx * u_xlat2 + _LeftColor;
    u_xlat16_3 = texture(_MainTex, vs_TEXCOORD0.xy);
    u_xlat16_4 = u_xlat2 * u_xlat16_3;
    u_xlat16_5.xyz = u_xlat16_4.xyz * _LightTint.xyz;
    u_xlat6.xyz = u_xlat16_5.xyz * _LightColor0.xyz + (-u_xlat8.xyz);
    u_xlat1.xyz = u_xlat0.xxx * u_xlat6.xyz + u_xlat8.xyz;
    u_xlat1.xyz = (-u_xlat2.xyz) * u_xlat16_3.xyz + u_xlat1.xyz;
    u_xlat1.xyz = vec3(vec3(_RampStrength, _RampStrength, _RampStrength)) * u_xlat1.xyz + u_xlat16_4.xyz;
    SV_Target0.w = u_xlat16_4.w;
    u_xlat16_5.xyz = u_xlat7.xyz * vec3(vec3(_UseSpecular, _UseSpecular, _UseSpecular)) + u_xlat1.xyz;
    u_xlat0.xyz = u_xlat16_5.xyz * vec3(_Brightness);
    SV_Target0.xyz = u_xlat0.xyz;
    return;
}
